#include <stdio.h>
int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        long long D, L, R;
        scanf("%lld %lld %lld", &D, &L, &R);
        if (D < L) printf("Too Early\n");
        else if (D > R) printf("Too Late\n");
        else printf("Take second dose now\n");
    }
    return 0;
}

