import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringTokenizer st = new StringTokenizer(br.readLine());
        int T = Integer.parseInt(st.nextToken());
        StringBuilder sb = new StringBuilder();
        for (int i = 0; i < T; i++) {
            st = new StringTokenizer(br.readLine());
            long D = Long.parseLong(st.nextToken());
            long L = Long.parseLong(st.nextToken());
            long R = Long.parseLong(st.nextToken());
            if (D < L) sb.append("Too Early\n");
            else if (D > R) sb.append("Too Late\n");
            else sb.append("Take second dose now\n");
        }
        System.out.print(sb.toString());
    }
}

code.Python3:
#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        D = int(next(it)); L = int(next(it)); R = int(next(it))
        if D < L:
            out_lines.append("Too Early")
        elif D > R:
            out_lines.append("Too Late")
        else:
            out_lines.append("Take second dose now")
    sys.stdout.write("\n".join(out_lines))

if __name__ == "__main__":
    solve()

